export const ALL_STUDENTS = RAW_STUDENTS.map(student => {
  const index = parseInt(student.rollNo.slice(-2), 10);
  let batchNum = 3;
  if (index >= 1 && index <= 20) batchNum = 1;
  else if (index >= 21 && index <= 40) batchNum = 2;
  student.batch = student.div + batchNum;
  return student;
});
